{
  "grammar": [
    {
      "pattern": "Subject + 想 + Verb + Object",
      "structure": ["Subject", "想", "Verb", "Object"],
      "explanation_en": "Use '想' to express a desire or intention to do something, similar to 'want to' in English.",
      "title": "Expressing Desire with 想",
      "meaning": "Want to do something",
      "when_to_use": ["When you want to suggest an activity", "When expressing personal wishes or plans"],
      "when_not_to_use": ["Do not use for future actions that are already arranged (use 要 instead)", "Do not use for polite requests (use 想要 or 可以 instead)"],
      "pragmatic_notes": "In Taiwan, 想 is softer than 要 and is often used to make suggestions sound less demanding. It's common in casual invitations.",
      "word_order_notes": "想 always comes after the subject and before the main verb. The object follows the verb.",
      "english_contrast": "English uses 'want to' before the verb, same as Chinese. However, Chinese does not conjugate 想 for tense or person.",
      "korean_contrast": "Korean uses '고 싶다' attached to the verb stem, while Chinese uses a separate word 想 before the verb.",
      "negative_examples": [
        {
          "text": "我想咖啡喝。",
          "error": "Wrong word order: the verb should come before the object."
        },
        {
          "text": "我昨天想喝咖啡。",
          "error": "想 is not used for past tense; use 想要 or context to indicate past desire."
        }
      ],
      "incorrect_examples": [
        {
          "text": "我想去咖啡店。",
          "error": "This sentence is actually correct. Use it as a model."
        }
      ],
      "transformation_drills": ["Change '我想喝咖啡' to '我想吃飯'", "Change '我想看電影' to '我想逛街'"],
      "production_drills": ["Say you want to meet a friend", "Say you want to drink coffee together"],
      "common_error_patterns": ["Placing the object before the verb", "Using 想 for fixed appointments"],
      "repair_feedback": {
        "word_order": "Remember: Subject + 想 + Verb + Object. For example: 我想喝咖啡.",
        "politeness": "想 is polite enough for casual invitations. For very polite requests, use 想要.",
        "vocabulary": "Use 想 for desires, not for scheduled events."
      }
    },
    {
      "pattern": "Subject + 要 + Verb + Object + (Time/Place)",
      "structure": ["Subject", "要", "Verb", "Object", "Time/Place"],
      "explanation_en": "Use '要' to indicate a planned or scheduled future action, similar to 'going to' or 'will' in English.",
      "title": "Future Plans with 要",
      "meaning": "Going to do something (planned)",
      "when_to_use": ["When you have a definite plan or appointment", "When asking about someone's schedule"],
      "when_not_to_use": ["Do not use for general desires (use 想 instead)", "Do not use for spontaneous decisions (use 會 instead)"],
      "pragmatic_notes": "In Taiwan, 要 implies a stronger commitment than 想. It's often used when plans are already made, like meeting someone.",
      "word_order_notes": "要 comes after the subject and before the verb. Time expressions can be placed before or after the subject.",
      "english_contrast": "English uses 'going to' or 'will' for future plans. Chinese 要 is more definite than 'will' and less flexible than 'going to'.",
      "korean_contrast": "Korean uses 'ㄹ 거예요' for future plans, which is similar to 要 in certainty. However, Korean attaches it to the verb, while Chinese uses a separate word.",
      "negative_examples": [
        {
          "text": "我要喝咖啡明天。",
          "error": "Time expression should come before the verb or at the beginning of the sentence."
        },
        {
          "text": "我不要喝咖啡。",
          "error": "This means 'I don't want to drink coffee', not a future plan. Use 不打算 for 'not planning to'."
        }
      ],
      "incorrect_examples": [
        {
          "text": "我明天要見朋友。",
          "error": "This sentence is correct. Use it as a model for planned actions."
        }
      ],
      "transformation_drills": ["Change '我明天要喝咖啡' to '我明天要吃飯'", "Change '我們要去看電影' to '我們要去逛街'"],
      "production_drills": ["Say you are going to meet a friend tomorrow", "Say you are going to drink coffee at a coffee shop"],
      "common_error_patterns": ["Using 要 for desires instead of plans", "Placing time expressions incorrectly"],
      "repair_feedback": {
        "word_order": "Place time before the verb: 我明天要見朋友.",
        "politeness": "要 is neutral. For polite invitations, use 想要 or 要不要.",
        "vocabulary": "Use 要 for definite plans, 想 for wishes."
      }
    },
    {
      "pattern": "Subject + 什麼時候 + Verb + Object?",
      "structure": ["Subject", "什麼時候", "Verb", "Object"],
      "explanation_en": "Use '什麼時候' to ask 'when' an action will happen. It is placed before the verb.",
      "title": "Asking When with 什麼時候",
      "meaning": "When will something happen?",
      "when_to_use": ["When asking about the time of a planned event", "When inquiring about someone's schedule"],
      "when_not_to_use": ["Do not use for duration (use 多久 instead)", "Do not use for frequency (use 幾次 instead)"],
      "pragmatic_notes": "In Taiwan, 什麼時候 is the standard way to ask 'when'. It can be used for both past and future events, but context clarifies.",
      "word_order_notes": "什麼時候 comes after the subject and before the verb. It cannot be placed at the end of the sentence.",
      "english_contrast": "English places 'when' at the beginning of the question. Chinese places 什麼時候 after the subject.",
      "korean_contrast": "Korean uses '언제' which is placed before the verb, similar to Chinese. However, Korean often omits the subject.",
      "negative_examples": [
        {
          "text": "你見朋友什麼時候？",
          "error": "什麼時候 should come before the verb, not at the end."
        },
        {
          "text": "什麼時候你見朋友？",
          "error": "什麼時候 cannot be at the beginning; it must follow the subject."
        }
      ],
      "incorrect_examples": [
        {
          "text": "你什麼時候見朋友？",
          "error": "This sentence is correct. Use it as a model."
        }
      ],
      "transformation_drills": ["Change '你什麼時候喝咖啡？' to '你什麼時候吃飯？'", "Change '你什麼時候看電影？' to '你什麼時候逛街？'"],
      "production_drills": ["Ask when someone will meet a friend", "Ask when someone will go to a coffee shop"],
      "common_error_patterns": ["Placing 什麼時候 at the beginning or end of the sentence", "Using 什麼時候 for duration"],
      "repair_feedback": {
        "word_order": "Place 什麼時候 after the subject: 你什麼時候見朋友？",
        "politeness": "什麼時候 is neutral. Add 請問 for politeness.",
        "vocabulary": "Use 什麼時候 for specific times, not for how long."
      }
    }
  ]
}
